+        1
+    );
+    assert!(!result.is_null());
+    assert_eq!(htab_filled(&htab), 1);
+
+    unsafe { frankenlibc_abi::errno_abi::set_abi_errno(0) };
+    let rc = unsafe { hcreate_r(32, &mut htab) };
+    assert_eq!(
+        rc, 0,
